     1→<script setup lang="ts">
     2→import { ref, onMounted } from "vue";
     3→import { calculateHoraryChart } from "../utils/astrology";
     4→
     5→interface QuestionData {
     6→  question: string;
     7→  timestamp: string;
     8→  location?: {
     9→    latitude: number;
    10→    longitude: number;
    11→  };
    12→  chartData: any;
    13→}
    14→
    15→const emit = defineEmits<{
    16→  (e: "chart-calculated", data: QuestionData): void;
    17→}>();
    18→
    19→const question = ref("");
    20→const error = ref("");
    21→const location = ref<{ latitude: number; longitude: number } | null>(null);
    22→const locationError = ref("");
    23→const isCalculating = ref(false);
    24→
    25→// Validate question length
    26→const validateQuestion = () => {
    27→  if (question.value.length < 10) {
    28→    error.value = "Question must be at least 10 characters long";
    29→    return false;
    30→  }
    31→  error.value = "";
    32→  return true;
    33→};
    34→
    35→// Get user's location
    36→const getLocation = async () => {
    37→  try {
    38→    const position = await new Promise<GeolocationPosition>(
    39→      (resolve, reject) => {
    40→        navigator.geolocation.getCurrentPosition(resolve, reject);
    41→      }
    42→    );
    43→
    44→    location.value = {
    45→      latitude: position.coords.latitude,
    46→      longitude: position.coords.longitude,
    47→    };
    48→  } catch (err) {
    49→    locationError.value = "Location access denied or unavailable";
    50→    console.error("Error getting location:", err);
    51→  }
    52→};
    53→
    54→// Handle form submission
    55→const handleSubmit = async () => {
    56→  if (!validateQuestion()) return;
    57→
    58→  try {
    59→    isCalculating.value = true;
    60→    if (!location.value) {
    61→      throw new Error("Location is required for horary calculations");
    62→    }
    63→
    64→    const chartData = await calculateHoraryChart(
    65→      new Date(),
    66→      location.value.latitude,
    67→      location.value.longitude
    68→    );
    69→
    70→    const horaryData = {
    71→      question: question.value,
    72→      timestamp: new Date().toISOString(),
    73→      location: location.value,
    74→      chartData,
    75→    };
    76→
    77→    emit("chart-calculated", horaryData);
    78→    question.value = ""; // Clear the question after successful submission
    79→  } catch (err) {
    80→    console.error("Error calculating chart:", err);
    81→    error.value =
    82→      err instanceof Error ? err.message : "Failed to calculate chart";
    83→  } finally {
    84→    isCalculating.value = false;
    85→  }
    86→};
    87→
    88→onMounted(() => {
    89→  getLocation();
    90→});
    91→</script>
