     4→// Enhanced format chart for LLM with aspect motion
     5→function formatChartForLLMWithMotion(reading: HoraryReading): string {
     6→  console.log(reading);
     7→  const chartData = reading.chartData;
     8→  let formattedData = `## Chart Data for Question: "${reading.question}"\n`;
     9→  formattedData += `**Time**: ${new Date(
    10→    reading.timestamp
    11→  ).toLocaleString()}\n`;
    12→
    13→  if (reading.location) {
    14→    formattedData += `**Location**: ${reading.location.latitude.toFixed(
    15→      2
    16→    )}°N, ${reading.location.longitude.toFixed(2)}°W\n\n`;
    17→  }
    18→
    19→  // Format planetary positions
    20→  formattedData += `### Planetary Positions:\n`;
    21→  Object.entries(chartData.planets).forEach(([planet, planetData]) => {
