   206→// Helper function to convert degrees to sign and degree
   207→function degreesToSignAndDegree(degrees: number): {
   208→  sign: string;
   209→  degree: number;
   210→} {
   211→  const signs = [
   212→    "Aries",
   213→    "Taurus",
   214→    "Gemini",
   215→    "Cancer",
   216→    "Leo",
   217→    "Virgo",
   218→    "Libra",
   219→    "Scorpio",
   220→    "Sagittarius",
   221→    "Capricorn",
   222→    "Aquarius",
   223→    "Pisces",
   224→  ];
   225→
   226→  const normalizedDegrees = ((degrees % 360) + 360) % 360;
   227→  const signIndex = Math.floor(normalizedDegrees / 30);
   228→  const degree = normalizedDegrees % 30;
   229→
   230→  return {
   231→    sign: signs[signIndex],
   232→    degree: Math.round(degree * 100) / 100,
   233→  };
   234→}
   235→
   236→// Helper function to determine house for a planet
   237→function getPlanetHouse(planetDegrees: number, cusps: number[]): number {
   238→  const normalizedPlanet = ((planetDegrees % 360) + 360) % 360;
   239→
   240→  for (let i = 0; i < cusps.length; i++) {
   241→    const currentCusp = ((cusps[i] % 360) + 360) % 360;
   242→    const nextCusp = ((cusps[(i + 1) % cusps.length] % 360) + 360) % 360;
   243→
   244→    if (nextCusp > currentCusp) {
   245→      if (normalizedPlanet >= currentCusp && normalizedPlanet < nextCusp) {
   246→        return i + 1;
   247→      }
   248→    } else {
   249→      if (normalizedPlanet >= currentCusp || normalizedPlanet < nextCusp) {
   250→        return i + 1;
   251→      }
   252→    }
   253→  }
   254→
   255→  return 1; // fallback
   256→}
