   342→  conversationHistory: Array<{ role: "user" | "assistant"; content: string }>,
   343→  newMessage: string
   344→): Promise<string | null> => {
   345→  try {
   346→    const formattedChart = formatChartForLLM(reading);
   347→
   348→    // Build the conversation with context
   349→    const messages = [
   350→      { role: "system" as const, content: HORARY_SYSTEM_PROMPT },
   351→      {
   352→        role: "user" as const,
   353→        content: `${formattedChart}\n\nPlease analyze this horary chart.`,
   354→      },
   355→      ...conversationHistory,
   356→      { role: "user" as const, content: newMessage },
   357→    ];
   358→
   359→    const response = await openai.chat.completions.create({
   360→      model: "llama3.2:latest",
   361→      messages,
   362→      temperature: 0.7,
   363→      max_tokens: 1500,
   364→    });
   365→
   366→    return response.choices[0].message.content;
   367→  } catch (error) {
   368→    console.error("Error in horary conversation:", error);
   369→    return null;
   370→  }
   371→};
   372→
   373→// Simple text generation for other purposes
   374→export const generateText = async (prompt: string): Promise<string | null> => {
   375→  try {
   376→    const response = await openai.chat.completions.create({
   377→      model: "llama3.2:latest",
   378→      messages: [{ role: "user", content: prompt }],
   379→    });
   380→
   381→    return response.choices[0].message.content;
   382→  } catch (error) {
   383→    console.error("Error generating text:", error);
   384→    return null;
   385→  }
   386→};
