     2→
     3→export interface PlanetData {
     4→  position: number;
     5→  isRetrograde: boolean;
     6→}
     7→
     8→export interface PlanetMotion {
     9→  position: number;
    10→  speed: number;
    11→  isRetrograde: boolean;
    12→}
    13→
    14→export interface AspectMotion {
    15→  aspectKey: string;
    16→  point1Key: string;
    17→  point2Key: string;
    18→  currentOrb: number;
    19→  isApplying: boolean;
    20→  isSeparating: boolean;
    21→  isPerfect: boolean;
    22→  timeToExact?: number;
    23→  timeSinceExact?: number;
    24→}
    25→
    26→const AVERAGE_DAILY_MOTION: { [key: string]: number } = {
    27→  sun: 0.9856,
    28→  moon: 13.1764,
    29→  mercury: 1.3833,
    30→  venus: 1.2,
    31→  mars: 0.524,
    32→  jupiter: 0.0831,
    33→  saturn: 0.0335,
    34→};
    35→
    36→// Updated to work with new chart data structure that includes retrograde status
    37→export function getPlanetMotion(
    38→  chartData: { planets: { [key: string]: PlanetData } },
    39→  planetKey: string
    40→): PlanetMotion {
    41→  try {
    42→    const planetData = chartData.planets[planetKey];
    43→
    44→    if (planetData) {
    45→      const baseSpeed = AVERAGE_DAILY_MOTION[planetKey] || 0;
    46→      // Apply negative speed for retrograde planets
    47→      const speed = planetData.isRetrograde ? -baseSpeed : baseSpeed;
    48→
    49→      return {
    50→        position: planetData.position,
    51→        speed,
    52→        isRetrograde: planetData.isRetrograde,
    53→      };
    54→    }
    55→
    56→    // Fallback if planet data is not found
    57→    return {
    58→      position: 0,
    59→      speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    60→      isRetrograde: false,
    61→    };
    62→  } catch (error) {
    63→    console.error(`Error getting motion for ${planetKey}:`, error);
    64→    return {
    65→      position: 0,
    66→      speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    67→      isRetrograde: false,
    68→    };
    69→  }
    70→}
    71→
    72→export function calculateAspectMotion(
    73→  chartData: { planets: { [key: string]: PlanetData } },
    74→  aspect: string
    75→): AspectMotion {
    76→  const planet1Motion = getPlanetMotion(chartData, aspect.split(" ")[0]);
    77→  const planet2Motion = getPlanetMotion(chartData, aspect.split(" ")[2]);
    78→
    79→  const aspectAngles: { [key: string]: number } = {
    80→    conjunction: 0,
    81→    sextile: 60,
    82→    square: 90,
    83→    trine: 120,
    84→    opposition: 180,
    85→  };
    86→
    87→  const targetAngle = aspectAngles[aspect.split(" ")[1]] || 0;
    88→
    89→  let separation = Math.abs(planet1Motion.position - planet2Motion.position);
    90→  if (separation > 180) separation = 360 - separation;
    91→
    92→  const relativeSpeed = Math.abs(planet1Motion.speed - planet2Motion.speed);
    93→
    94→  const futurePos1 = planet1Motion.position + planet1Motion.speed;
    95→  const futurePos2 = planet2Motion.position + planet2Motion.speed;
    96→
    97→  let futureSeparation = Math.abs(futurePos1 - futurePos2);
    98→  if (futureSeparation > 180) futureSeparation = 360 - futureSeparation;
    99→
   100→  const futureOrb = Math.abs(futureSeparation - targetAngle);
   101→  const currentOrb = Math.abs(separation - targetAngle);
   102→
   103→  const isApplying = futureOrb < currentOrb;
   104→  const isSeparating = futureOrb > currentOrb;
   105→  const isPerfect = currentOrb <= 1;
   106→
   107→  let timeToExact: number | undefined;
   108→  let timeSinceExact: number | undefined;
   109→
   110→  if (relativeSpeed > 0) {
   111→    if (isApplying) {
   112→      timeToExact = currentOrb / relativeSpeed;
   113→    } else if (isSeparating) {
   114→      timeSinceExact = currentOrb / relativeSpeed;
   115→    }
   116→  }
   117→
   118→  return {
   119→    aspectKey: aspect.split(" ")[1],
   120→    point1Key: aspect.split(" ")[0],
   121→    point2Key: aspect.split(" ")[2],
   122→    currentOrb: currentOrb,
   123→    isApplying,
   124→    isSeparating,
   125→    isPerfect,
   126→    timeToExact,
   127→    timeSinceExact,
   128→  };
   129→}
   130→
   131→export function extractAspectsWithMotion(
   132→  chartData: { planets: { [key: string]: PlanetData } },
   133→  basicAspects: any[]
   134→): Array<
   135→  AspectMotion & {
   136→    point1Label: string;
   137→    point2Label: string;
   138→    aspectLabel: string;
   139→  }
   140→> {
   141→  console.log(chartData, basicAspects);
   142→  return basicAspects.map((aspect) => {
   143→    const motionData = calculateAspectMotion(chartData, aspect);
   144→    console.log(aspect);
   145→    console.log(motionData);
   146→    return {
   147→      ...motionData,
   148→      point1Label: aspect.split(" ")[0],
   149→      point2Label: aspect.split(" ")[2],
   150→      aspectLabel: aspect.split(" ")[1],
   151→    };
   152→  });
   153→}
   154→
   155→export function analyzeMoonAspects(
   156→  aspectsWithMotion: Array<
   157→    AspectMotion & {
   158→      point1Label: string;
   159→      point2Label: string;
   160→      aspectLabel: string;
   161→    }
   162→  >
   163→): {
   164→  separatingAspects: Array<
   165→    AspectMotion & {
   166→      point1Label: string;
   167→      point2Label: string;
   168→      aspectLabel: string;
   169→    }
   170→  >;
   171→  applyingAspects: Array<
   172→    AspectMotion & {
   173→      point1Label: string;
   174→      point2Label: string;
   175→      aspectLabel: string;
   176→    }
   177→  >;
   178→  nextApplyingAspect?: AspectMotion & {
   179→    point1Label: string;
   180→    point2Label: string;
   181→    aspectLabel: string;
   182→  };
   183→  lastSeparatingAspect?: AspectMotion & {
   184→    point1Label: string;
   185→    point2Label: string;
   186→    aspectLabel: string;
   187→  };
   188→} {
   189→  // Filter for aspects involving the Moon
   190→  const moonAspects = aspectsWithMotion.filter(
   191→    (aspect) => aspect.point1Key === "moon" || aspect.point2Key === "moon"
   192→  );
   193→  console.log(moonAspects);
   194→  // Separate applying and separating aspects
   195→  const separatingAspects = moonAspects.filter((a) => a.isSeparating);
   196→  const applyingAspects = moonAspects.filter((a) => a.isApplying);
   197→
   198→  // Find the closest separating aspect (smallest orb = most recent)
   199→  const lastSeparatingAspect =
   200→    separatingAspects.length > 0
   201→      ? separatingAspects.reduce((closest, current) =>
   202→          current.currentOrb < closest.currentOrb ? current : closest
   203→        )
   204→      : undefined;
   205→
   206→  // Find the closest applying aspect (smallest orb = next to perfect)
   207→  const nextApplyingAspect =
   208→    applyingAspects.length > 0
   209→      ? applyingAspects.reduce((closest, current) =>
   210→          current.currentOrb < closest.currentOrb ? current : closest
   211→        )
   212→      : undefined;
   213→
   214→  return {
   215→    separatingAspects,
   216→    applyingAspects,
   217→    nextApplyingAspect,
   218→    lastSeparatingAspect,
   219→  };
   220→}
   221→
   222→export function formatAspectMotionForLLM(aspectMotion: AspectMotion[]): string {
   223→  let formatted = "\n### Aspect Motion Analysis:\n\n";
   224→
   225→  aspectMotion.forEach((aspect) => {
   226→    const status = aspect.isApplying
   227→      ? "Applying"
   228→      : aspect.isSeparating
   229→      ? "Separating"
   230→      : "Stable";
   231→
   232→    formatted += `- **${aspect.point1Key} ${aspect.aspectKey} ${aspect.point2Key}**: `;
   233→    formatted += `${status} (orb: ${aspect.currentOrb.toFixed(2)}°)`;
   234→
   235→    if (aspect.timeToExact) {
   236→      formatted += ` - exact in ${aspect.timeToExact.toFixed(1)} days`;
   237→    } else if (aspect.timeSinceExact) {
   238→      formatted += ` - was exact ${aspect.timeSinceExact.toFixed(1)} days ago`;
   239→    }
   240→
   241→    if (aspect.isPerfect) {
   242→      formatted += " **[PERFECT ASPECT]**";
   243→    }
   244→
   245→    formatted += "\n";
   246→  });
   247→
   248→  return formatted;
   249→}
