     2→
     3→interface PlanetData {
     4→  position: number;
     5→  isRetrograde: boolean;
     6→}
     7→
     8→interface Planets {
     9→  [key: string]: PlanetData;
    10→}
    11→
    12→const points = ["sun", "moon", "mercury", "venus", "mars", "jupiter", "saturn"];
    13→
    14→export function calculateHoraryChart(
    15→  timestamp: Date,
    16→  latitude: number,
    17→  longitude: number,
    18→): any {
    19→  const origin = new Origin({
    20→    year: timestamp.getFullYear(),
    21→    month: timestamp.getMonth(),
    22→    date: timestamp.getDate(),
    23→    hour: timestamp.getHours(),
    24→    minute: timestamp.getMinutes(),
    25→    second: timestamp.getSeconds(),
    26→    latitude,
    27→    longitude,
    28→  });
    29→  const horoscope = new Horoscope({
    30→    origin,
    31→    houseSystem: "whole-sign",
    32→    zodiac: "tropical",
    33→    aspectPoints: ["bodies"],
    34→    aspectWithPoints: ["bodies"],
    35→    aspectTypes: ["major"],
    36→    customOrbs: {
    37→      conjunction: 8,
    38→      opposition: 8,
    39→      trine: 8,
    40→      square: 7,
    41→      sextile: 6,
    42→    },
    43→    language: "en",
    44→  });
    45→  const planets: Planets = {};
    46→  horoscope.CelestialBodies.all.map(
    47→    (body: {
    48→      key: string;
    49→      ChartPosition: { Ecliptic: { DecimalDegrees: number } };
    50→      isRetrograde?: boolean;
    51→    }) => {
    52→      if (points.includes(body.key as string)) {
    53→        planets[body.key] = {
    54→          position: body.ChartPosition.Ecliptic.DecimalDegrees,
    55→          isRetrograde: body.isRetrograde ?? false,
    56→        };
    57→      }
    58→    },
    59→  );
    60→  planets["ascendant"] = {
    61→    position: horoscope.Ascendant.ChartPosition.Ecliptic.DecimalDegrees,
    62→    isRetrograde: false,
    63→  };
    64→  planets["midheaven"] = {
    65→    position: horoscope.Midheaven.ChartPosition.Ecliptic.DecimalDegrees,
    66→    isRetrograde: false,
    67→  };
    68→  const houseCusps: number[] = horoscope.Houses.map(
    69→    (house: {
    70→      ChartPosition: {
    71→        StartPosition: { Ecliptic: { DecimalDegrees: number } };
    72→      };
    73→    }) => {
    74→      return house.ChartPosition.StartPosition.Ecliptic.DecimalDegrees;
    75→    },
    76→  );
    77→  // filter out traditional aspects and planets
    78→  const aspects: Record<string, Array<{
    79→    aspectLevel: string;
    80→    point1Key: string;
    81→    point2Key: string;
    82→    aspectKey: string;
    83→  }>> = { ...horoscope.Aspects.points };
    84→  let tradAspects: string[] = [];
    85→  for (const planet in aspects) {
    86→    if (points.includes(planet.toString())) {
    87→      const planetAspects = aspects[planet]
    88→        .filter(
    89→          (aspect) =>
    90→            aspect.aspectLevel === "major" &&
    91→            points.includes(aspect.point1Key.toString()) &&
    92→            points.includes(aspect.point2Key.toString()),
    93→        )
    94→        .map((aspect) => {
    95→          return `${aspect.point1Key} ${aspect.aspectKey} ${aspect.point2Key}`;
    96→        });
    97→      tradAspects = tradAspects.concat(planetAspects);
    98→    }
    99→  }
   100→  const uniqueAspects = [...new Set(tradAspects)];
   101→  return {
   102→    planets: planets,
   103→    cusps: houseCusps,
   104→    aspects: uniqueAspects,
   105→  };
   106→}
