   258→// Format chart data for the LLM
   259→function formatChartForLLM(reading: HoraryReading): string {
   260→  const { chartData } = reading;
   261→
   262→  let formattedData = `## Chart Data for Question: "${reading.question}"\n`;
   263→  formattedData += `**Time**: ${new Date(
   264→    reading.timestamp
   265→  ).toLocaleString()}\n`;
   266→
   267→  if (reading.location) {
   268→    formattedData += `**Location**: ${reading.location.latitude.toFixed(
   269→      2
   270→    )}°N, ${reading.location.longitude.toFixed(2)}°W\n\n`;
   271→  }
   272→
   273→  // Format planetary positions
   274→  formattedData += `### Planetary Positions:\n`;
   275→  Object.entries(chartData.planets).forEach(([planet, planetData]) => {
   276→    const { sign, degree } = degreesToSignAndDegree(planetData.position);
   277→    const house = getPlanetHouse(planetData.position, chartData.cusps);
   278→    const rxSymbol = planetData.isRetrograde ? " ℞" : "";
   279→    formattedData += `- **${
   280→      planet.charAt(0).toUpperCase() + planet.slice(1)
   281→    }${rxSymbol}**: ${degree.toFixed(2)}° ${sign} (House ${house})\n`;
   282→  });
   283→
   284→  // Format house cusps
   285→  formattedData += `\n### House Cusps:\n`;
   286→  chartData.cusps.forEach((cusp, index) => {
   287→    const { sign, degree } = degreesToSignAndDegree(cusp);
   288→    formattedData += `- **House ${index + 1}**: ${degree.toFixed(
   289→      2
   290→    )}° ${sign}\n`;
   291→  });
   292→
   293→  // Add aspects if available
   294→  if (chartData.aspects && chartData.aspects.length > 0) {
   295→    formattedData += `\n### Major Aspects:\n`;
   296→    chartData.aspects.forEach((aspect) => {
   297→      formattedData += `- ${aspect}\n`;
   298→    });
   299→  }
   300→
   301→  return formattedData;
   302→}
