   139→  }
   140→> {
   141→  console.log(chartData, basicAspects);
   142→  return basicAspects.map((aspect) => {
   143→    const motionData = calculateAspectMotion(chartData, aspect);
   144→    console.log(aspect);
   145→    console.log(motionData);
   146→    return {
   147→      ...motionData,
