   154→
   155→export function analyzeMoonAspects(
   156→  aspectsWithMotion: Array<
   157→    AspectMotion & {
   158→      point1Label: string;
   159→      point2Label: string;
   160→      aspectLabel: string;
   161→    }
   162→  >
   163→): {
   164→  separatingAspects: Array<
   165→    AspectMotion & {
   166→      point1Label: string;
   167→      point2Label: string;
   168→      aspectLabel: string;
   169→    }
   170→  >;
   171→  applyingAspects: Array<
   172→    AspectMotion & {
   173→      point1Label: string;
   174→      point2Label: string;
   175→      aspectLabel: string;
   176→    }
   177→  >;
   178→  nextApplyingAspect?: AspectMotion & {
   179→    point1Label: string;
   180→    point2Label: string;
   181→    aspectLabel: string;
   182→  };
   183→  lastSeparatingAspect?: AspectMotion & {
   184→    point1Label: string;
   185→    point2Label: string;
   186→    aspectLabel: string;
   187→  };
   188→} {
   189→  // Filter for aspects involving the Moon
   190→  const moonAspects = aspectsWithMotion.filter(
   191→    (aspect) => aspect.point1Key === "moon" || aspect.point2Key === "moon"
   192→  );
   193→  console.log(moonAspects);
   194→  // Separate applying and separating aspects
   195→  const separatingAspects = moonAspects.filter((a) => a.isSeparating);
   196→  const applyingAspects = moonAspects.filter((a) => a.isApplying);
   197→
   198→  // Find the closest separating aspect (smallest orb = most recent)
   199→  const lastSeparatingAspect =
   200→    separatingAspects.length > 0
   201→      ? separatingAspects.reduce((closest, current) =>
   202→          current.currentOrb < closest.currentOrb ? current : closest
   203→        )
   204→      : undefined;
   205→
   206→  // Find the closest applying aspect (smallest orb = next to perfect)
   207→  const nextApplyingAspect =
   208→    applyingAspects.length > 0
   209→      ? applyingAspects.reduce((closest, current) =>
   210→          current.currentOrb < closest.currentOrb ? current : closest
   211→        )
   212→      : undefined;
   213→
   214→  return {
   215→    separatingAspects,
   216→    applyingAspects,
   217→    nextApplyingAspect,
   218→    lastSeparatingAspect,
   219→  };
   220→}
