   222→export function formatAspectMotionForLLM(aspectMotion: AspectMotion[]): string {
   223→  let formatted = "\n### Aspect Motion Analysis:\n\n";
   224→
   225→  aspectMotion.forEach((aspect) => {
   226→    const status = aspect.isApplying
   227→      ? "Applying"
   228→      : aspect.isSeparating
   229→      ? "Separating"
   230→      : "Stable";
   231→
   232→    formatted += `- **${aspect.point1Key} ${aspect.aspectKey} ${aspect.point2Key}**: `;
   233→    formatted += `${status} (orb: ${aspect.currentOrb.toFixed(2)}°)`;
   234→
   235→    if (aspect.timeToExact) {
   236→      formatted += ` - exact in ${aspect.timeToExact.toFixed(1)} days`;
   237→    } else if (aspect.timeSinceExact) {
   238→      formatted += ` - was exact ${aspect.timeSinceExact.toFixed(1)} days ago`;
   239→    }
   240→
   241→    if (aspect.isPerfect) {
   242→      formatted += " **[PERFECT ASPECT]**";
   243→    }
   244→
   245→    formatted += "\n";
   246→  });
   247→
   248→  return formatted;
   249→}
