     2→// Simple localStorage implementation for now, can be replaced with a proper database later
     3→
     4→export interface StoredReading {
     5→  id: string;
     6→  question: string;
     7→  timestamp: string;
     8→  location?: {
     9→    latitude: number;
    10→    longitude: number;
    11→  };
    12→  chartData: any;
    13→  conversation: Array<{
    14→    role: "user" | "assistant";
    15→    content: string;
    16→    timestamp: string;
    17→  }>;
    18→  tags?: string[];
    19→}
    20→
    21→class ReadingStorage {
    22→  private readonly STORAGE_KEY = "horary_readings";
    23→
    24→  // Save a new reading
    25→  saveReading(reading: Omit<StoredReading, "id">): string {
    26→    const id = this.generateId();
    27→    const storedReading: StoredReading = {
    28→      ...reading,
    29→      id,
    30→    };
    31→
    32→    const readings = this.getAllReadings();
    33→    readings.push(storedReading);
    34→
    35→    try {
    36→      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(readings));
    37→      return id;
    38→    } catch (error) {
    39→      console.error("Error saving reading:", error);
    40→      throw new Error("Failed to save reading");
    41→    }
    42→  }
    43→
    44→  // Update an existing reading (e.g., add conversation messages)
    45→  updateReading(id: string, updates: Partial<StoredReading>): void {
    46→    const readings = this.getAllReadings();
    47→    const index = readings.findIndex((r) => r.id === id);
    48→
    49→    if (index === -1) {
    50→      throw new Error("Reading not found");
    51→    }
    52→
    53→    readings[index] = { ...readings[index], ...updates };
    54→
    55→    try {
    56→      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(readings));
    57→    } catch (error) {
    58→      console.error("Error updating reading:", error);
    59→      throw new Error("Failed to update reading");
    60→    }
    61→  }
    62→
    63→  // Get all readings
    64→  getAllReadings(): StoredReading[] {
    65→    try {
    66→      const stored = localStorage.getItem(this.STORAGE_KEY);
    67→      return stored ? JSON.parse(stored) : [];
    68→    } catch (error) {
    69→      console.error("Error loading readings:", error);
    70→      return [];
    71→    }
    72→  }
    73→
    74→  // Get a specific reading by ID
    75→  getReading(id: string): StoredReading | null {
    76→    const readings = this.getAllReadings();
    77→    return readings.find((r) => r.id === id) || null;
    78→  }
    79→
    80→  // Delete a reading
    81→  deleteReading(id: string): void {
    82→    const readings = this.getAllReadings();
    83→    const filtered = readings.filter((r) => r.id !== id);
    84→
    85→    try {
    86→      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(filtered));
    87→    } catch (error) {
    88→      console.error("Error deleting reading:", error);
    89→      throw new Error("Failed to delete reading");
    90→    }
    91→  }
    92→
    93→  // Search readings by question text
    94→  searchReadings(query: string): StoredReading[] {
    95→    const readings = this.getAllReadings();
    96→    const lowercaseQuery = query.toLowerCase();
    97→
    98→    return readings.filter(
    99→      (reading) =>
   100→        reading.question.toLowerCase().includes(lowercaseQuery) ||
   101→        reading.tags?.some((tag) => tag.toLowerCase().includes(lowercaseQuery))
   102→    );
   103→  }
   104→
   105→  // Get readings by date range
   106→  getReadingsByDateRange(startDate: Date, endDate: Date): StoredReading[] {
   107→    const readings = this.getAllReadings();
   108→
   109→    return readings.filter((reading) => {
   110→      const readingDate = new Date(reading.timestamp);
   111→      return readingDate >= startDate && readingDate <= endDate;
   112→    });
   113→  }
   114→
   115→  // Export readings as JSON
   116→  exportReadings(): string {
   117→    const readings = this.getAllReadings();
   118→    return JSON.stringify(readings, null, 2);
   119→  }
   120→
   121→  // Import readings from JSON
   122→  importReadings(jsonData: string): void {
   123→    try {
   124→      const importedReadings = JSON.parse(jsonData);
   125→      if (!Array.isArray(importedReadings)) {
   126→        throw new Error("Invalid format");
   127→      }
   128→
   129→      // Validate structure (basic check)
   130→      importedReadings.forEach((reading) => {
   131→        if (!reading.id || !reading.question || !reading.timestamp) {
   132→          throw new Error("Invalid reading structure");
   133→        }
   134→      });
   135→
   136→      localStorage.setItem(this.STORAGE_KEY, jsonData);
   137→    } catch (error) {
   138→      console.error("Error importing readings:", error);
   139→      throw new Error("Failed to import readings");
   140→    }
   141→  }
   142→
   143→  // Generate a unique ID
   144→  private generateId(): string {
   145→    return Date.now().toString(36) + Math.random().toString(36).substr(2);
   146→  }
   147→
   148→  // Get storage usage stats
   149→  getStorageStats(): {
   150→    totalReadings: number;
   151→    oldestReading: string | null;
   152→    newestReading: string | null;
   153→    storageSize: number;
   154→  } {
   155→    const readings = this.getAllReadings();
   156→    const storageData = localStorage.getItem(this.STORAGE_KEY) || "";
   157→
   158→    return {
   159→      totalReadings: readings.length,
   160→      oldestReading:
   161→        readings.length > 0
   162→          ? readings.reduce((oldest, current) =>
   163→              new Date(current.timestamp) < new Date(oldest.timestamp)
   164→                ? current
   165→                : oldest
   166→            ).timestamp
   167→          : null,
   168→      newestReading:
   169→        readings.length > 0
   170→          ? readings.reduce((newest, current) =>
   171→              new Date(current.timestamp) > new Date(newest.timestamp)
   172→                ? current
   173→                : newest
   174→            ).timestamp
   175→          : null,
   176→      storageSize: new Blob([storageData]).size,
   177→    };
   178→  }
   179→}
   180→
   181→// Create and export a singleton instance
   182→export const readingStorage = new ReadingStorage();
   183→
   184→// Hook for Vue components
   185→export function useReadingStorage() {
   186→  return {
   187→    saveReading: readingStorage.saveReading.bind(readingStorage),
   188→    updateReading: readingStorage.updateReading.bind(readingStorage),
   189→    getAllReadings: readingStorage.getAllReadings.bind(readingStorage),
   190→    getReading: readingStorage.getReading.bind(readingStorage),
   191→    deleteReading: readingStorage.deleteReading.bind(readingStorage),
   192→    searchReadings: readingStorage.searchReadings.bind(readingStorage),
   193→    getReadingsByDateRange:
   194→      readingStorage.getReadingsByDateRange.bind(readingStorage),
   195→    exportReadings: readingStorage.exportReadings.bind(readingStorage),
   196→    importReadings: readingStorage.importReadings.bind(readingStorage),
   197→    getStorageStats: readingStorage.getStorageStats.bind(readingStorage),
   198→  };
   199→}
