    13→const readings = ref<StoredReading[]>([]);
    14→const searchQuery = ref("");
    15→const isLoading = ref(false);
    16→const showConfirmDelete = ref(false);
    17→const readingToDelete = ref<StoredReading | null>(null);
    18→
    19→// Computed filtered readings
    20→const filteredReadings = computed(() => {
    21→  if (!searchQuery.value.trim()) {
    22→    return readings.value;
    23→  }
    24→  return searchReadings(searchQuery.value);
    25→});
    26→
    27→// Group readings by date
    28→const groupedReadings = computed(() => {
    29→  const groups: { [key: string]: StoredReading[] } = {};
    30→
    31→  filteredReadings.value.forEach((reading) => {
    32→    const date = new Date(reading.timestamp).toLocaleDateString();
    33→    if (!groups[date]) {
    34→      groups[date] = [];
    35→    }
    36→    groups[date].push(reading);
    37→  });
    38→
    39→  // Sort by date (newest first)
    40→  const sortedGroups = Object.entries(groups).sort(
    41→    ([a], [b]) => new Date(b).getTime() - new Date(a).getTime()
    42→  );
    43→
    44→  return sortedGroups;
    45→});
    46→
    47→// Storage stats
    48→const storageStats = ref(getStorageStats());
    49→
    50→// Load readings
    51→const loadReadings = async () => {
    52→  isLoading.value = true;
    53→  try {
    54→    readings.value = getAllReadings().sort(
    55→      (a, b) =>
    56→        new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    57→    );
    58→    storageStats.value = getStorageStats();
    59→  } catch (error) {
    60→    console.error("Error loading readings:", error);
    61→  } finally {
    62→    isLoading.value = false;
    63→  }
    64→};
    65→
    66→// Select a reading
    67→const selectReading = (reading: StoredReading) => {
    68→  emit("select-reading", reading);
    69→};
    70→
    71→// Confirm delete
    72→const confirmDelete = (reading: StoredReading) => {
    73→  readingToDelete.value = reading;
    74→  showConfirmDelete.value = true;
    75→};
    76→
    77→// Delete reading
    78→const handleDelete = async () => {
    79→  if (!readingToDelete.value) return;
    80→
    81→  try {
    82→    deleteReading(readingToDelete.value.id);
    83→    await loadReadings();
    84→    showConfirmDelete.value = false;
    85→    readingToDelete.value = null;
    86→  } catch (error) {
    87→    console.error("Error deleting reading:", error);
    88→  }
    89→};
    90→
    91→// Truncate question
    92→const truncateQuestion = (question: string, maxLength: number = 100) => {
    93→  return question.length > maxLength
    94→    ? question.substring(0, maxLength) + "..."
    95→    : question;
    96→};
    97→
    98→onMounted(loadReadings);
    99→</script>
