    25→
    26→const AVERAGE_DAILY_MOTION: { [key: string]: number } = {
    27→  sun: 0.9856,
    28→  moon: 13.1764,
    29→  mercury: 1.3833,
    30→  venus: 1.2,
    31→  mars: 0.524,
    32→  jupiter: 0.0831,
    33→  saturn: 0.0335,
    34→};
    35→
    36→// Updated to work with new chart data structure that includes retrograde status
    37→export function getPlanetMotion(
    38→  chartData: { planets: { [key: string]: PlanetData } },
    39→  planetKey: string
    40→): PlanetMotion {
    41→  try {
    42→    const planetData = chartData.planets[planetKey];
    43→
    44→    if (planetData) {
    45→      const baseSpeed = AVERAGE_DAILY_MOTION[planetKey] || 0;
    46→      // Apply negative speed for retrograde planets
    47→      const speed = planetData.isRetrograde ? -baseSpeed : baseSpeed;
    48→
    49→      return {
    50→        position: planetData.position,
    51→        speed,
    52→        isRetrograde: planetData.isRetrograde,
    53→      };
    54→    }
    55→
    56→    // Fallback if planet data is not found
    57→    return {
    58→      position: 0,
    59→      speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    60→      isRetrograde: false,
    61→    };
    62→  } catch (error) {
    63→    console.error(`Error getting motion for ${planetKey}:`, error);
    64→    return {
    65→      position: 0,
    66→      speed: AVERAGE_DAILY_MOTION[planetKey] || 0,
    67→      isRetrograde: false,
    68→    };
    69→  }
    70→}
    71→
    72→export function calculateAspectMotion(
    73→  chartData: { planets: { [key: string]: PlanetData } },
    74→  aspect: string
    75→): AspectMotion {
    76→  const planet1Motion = getPlanetMotion(chartData, aspect.split(" ")[0]);
    77→  const planet2Motion = getPlanetMotion(chartData, aspect.split(" ")[2]);
    78→
    79→  const aspectAngles: { [key: string]: number } = {
    80→    conjunction: 0,
    81→    sextile: 60,
    82→    square: 90,
    83→    trine: 120,
    84→    opposition: 180,
    85→  };
    86→
    87→  const targetAngle = aspectAngles[aspect.split(" ")[1]] || 0;
    88→
    89→  let separation = Math.abs(planet1Motion.position - planet2Motion.position);
    90→  if (separation > 180) separation = 360 - separation;
    91→
    92→  const relativeSpeed = Math.abs(planet1Motion.speed - planet2Motion.speed);
    93→
    94→  const futurePos1 = planet1Motion.position + planet1Motion.speed;
    95→  const futurePos2 = planet2Motion.position + planet2Motion.speed;
    96→
    97→  let futureSeparation = Math.abs(futurePos1 - futurePos2);
    98→  if (futureSeparation > 180) futureSeparation = 360 - futureSeparation;
    99→
   100→  const futureOrb = Math.abs(futureSeparation - targetAngle);
   101→  const currentOrb = Math.abs(separation - targetAngle);
   102→
   103→  const isApplying = futureOrb < currentOrb;
   104→  const isSeparating = futureOrb > currentOrb;
   105→  const isPerfect = currentOrb <= 1;
   106→
   107→  let timeToExact: number | undefined;
   108→  let timeSinceExact: number | undefined;
   109→
   110→  if (relativeSpeed > 0) {
   111→    if (isApplying) {
   112→      timeToExact = currentOrb / relativeSpeed;
   113→    } else if (isSeparating) {
   114→      timeSinceExact = currentOrb / relativeSpeed;
   115→    }
   116→  }
   117→
   118→  return {
   119→    aspectKey: aspect.split(" ")[1],
   120→    point1Key: aspect.split(" ")[0],
   121→    point2Key: aspect.split(" ")[2],
   122→    currentOrb: currentOrb,
   123→    isApplying,
   124→    isSeparating,
   125→    isPerfect,
   126→    timeToExact,
   127→    timeSinceExact,
   128→  };
   129→}
